var e=JSON.parse(`[{"id":"L3_1","type":"dialog","speaker":"PRINCIPAL_NPC_ORPHAN_NULL","text":{"KOREA":"……그래서.","JPN":"……つまり。","ENG":"...So.","TWN":"……所以呢？"},"stage":{"bg":"DORMITORY_3","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SPEAKER_DEBT_NECK_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L4_1","type":"dialog","speaker":"PRINCIPAL_NPC_ORPHAN_NULL","text":{"KOREA":"그대로 병원에 실려가 몇 주간 입원해 있었다?","JPN":"そのまま病院に運ばれて、何週間も入院していたと？","ENG":"That's how you ended up in the hospital for several weeks?","TWN":"就這樣被送進醫院住了幾周？"},"stage":{"bg":"DORMITORY_3","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SPEAKER_DEBT_NECK_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L5_1","type":"dialog","speaker":"SPEAKER_DEBT_NECK_NULL","text":{"KOREA":"그런 식으로 쳐다보지 마세요. 딱히 병원비 문제로 손 빌리지도 않았잖아요.","JPN":"そんな目で見ないでください。病院代は自腹で払ったんですから。","ENG":"Don't look at me like that. I didn't ask you for help in paying the hospital bills.","TWN":"不、不要那樣看著我。我又沒有因為醫藥費問題向你借錢……"},"stage":{"bg":"DORMITORY_3","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SPEAKER_DEBT_NECK_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L7_1","type":"dialog","speaker":"PRINCIPAL_NPC_ORPHAN_NULL","text":{"KOREA":"누가 돈 때문이래? 난 네가 보육원 때문에 범죄자가 된 줄 알고 잠도 못 잤다, 야.","JPN":"そういう問題か？　私は孤児院が原因で君が犯罪者になったのかと思って、夜も眠れなかったんだ。","ENG":"This isn't about money. I lost sleep thinking that you became a criminal because of the orphanage.","TWN":"這是錢的問題嗎？我以為你因為育幼院成了罪犯，連覺都睡不著！"},"stage":{"bg":"DORMITORY_3","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SPEAKER_DEBT_NECK_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L8_1","type":"dialog","speaker":"SPEAKER_DEBT_NECK_NULL","text":{"KOREA":"아하하… 결과가 좋으면 됐죠.","JPN":"あはは……結果オーライってことでいいじゃないですか。","ENG":"Ah ha ha... All's well that ends well.","TWN":"哈哈哈……結果是好的就行了……"},"stage":{"bg":"DORMITORY_3","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SPEAKER_DEBT_NECK_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L9_1","type":"dialog","speaker":"SPEAKER_DEBT_NECK_NULL","text":{"KOREA":"그런데 원장님. 일은 어쩌고 지금 시간에 여기 계세요?","JPN":"ところで、園長。業務時間内にこんなところにいても大丈夫なんですか？","ENG":"By the way, what are you doing here at this hour? What about your job?","TWN":"不過，院長，工作怎麼辦？你怎麼在這個時間跑過來？"},"stage":{"bg":"DORMITORY_3","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SPEAKER_DEBT_NECK_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L10_1","type":"dialog","speaker":"SPEAKER_DEBT_NECK_NULL","text":{"KOREA":"설마 잘리셨어요?","JPN":"もしかしてクビになったとか？","ENG":"Were you fired?","TWN":"難道是被解雇了？"},"stage":{"bg":"DORMITORY_3","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SPEAKER_DEBT_NECK_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L12_1","type":"dialog","speaker":"PRINCIPAL_NPC_ORPHAN_NULL","text":{"KOREA":"넌 뭔 말을 그렇게 하냐? 그런 게 아니라 오늘 중요한 미팅이 있어서 그래.","JPN":"そういう発想はやめてくれ。今日は大事なミーティングがあるんだ。","ENG":"What are you talking about? I just had an important meeting today.","TWN":"說話怎麼不動動腦子呢？我今天是有個重要的會議。"},"stage":{"bg":"DORMITORY_3","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SPEAKER_DEBT_NECK_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L13_1","type":"dialog","speaker":"PRINCIPAL_NPC_ORPHAN_NULL","text":{"KOREA":"실은 네가 입원한 사이에 보육원에 후원자가 생겼거든.","JPN":"実は君が入院している間、孤児院を後援してくれる人が現れたんだ。","ENG":"The orphanage actually got a sponsor while you were in the hospital.","TWN":"其實在你住院期間，育幼院有了資助者。"},"stage":{"bg":"DORMITORY_3","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SPEAKER_DEBT_NECK_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":"SPEAKER_DEBT_NECK_NULL","text":{"KOREA":"후원자요? 이런 허름한 보육원이 뭐가 좋다고 그런 걸 한대요?","JPN":"後援？　こんなボロい孤児院を、いったいどんな物好きが？","ENG":"A sponsor? Why would they sponsor a raggedy orphanage like this?","TWN":"資助者？這個破育幼院有什麼好資助的？"},"stage":{"bg":"DORMITORY_3","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SPEAKER_DEBT_NECK_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":"PRINCIPAL_NPC_ORPHAN_NULL","text":{"KOREA":"나도 몰라. 듣기로는 재벌 2세라는데 이미지 메이킹이라도 하려나 보지.","JPN":"私もよくは知らん。財閥2世だそうだが、イメージアップでもしたいんだろう。","ENG":"I don't know. I heard she was from a wealthy family. I guess she's trying to look generous or something.","TWN":"我也不知道。聽說是富二代，可能是想打造形象吧。"},"stage":{"bg":"DORMITORY_3","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SPEAKER_DEBT_NECK_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L20_1","type":"dialog","speaker":"PRINCIPAL_NPC_ORPHAN_NULL","text":{"KOREA":"마침 오셨네. 난 다과나 준비할 테니 네가 잘 안내해 드려라.","JPN":"ちょうどいらっしゃったぞ。私はお菓子を用意してくるから、案内は君に任せた。","ENG":"Ah, she's here. I'm going to prepare some snacks, so show her in.","TWN":"喔，人來了。我去準備點心，你好好招待客人吧。"},"stage":{"bg":"DORMITORY_3","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SPEAKER_DEBT_NECK_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L21_1","type":"dialog","speaker":"SPEAKER_DEBT_NECK_NULL","text":{"KOREA":"네. 일 보세요.","JPN":"はい、いってらっしゃい。","ENG":"Will do.","TWN":"是，院長去忙吧。"},"stage":{"bg":"DORMITORY_3","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SPEAKER_DEBT_NECK_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L23_1","type":"dialog","speaker":"SPEAKER_DEBT_NECK_NULL","text":{"KOREA":"신기하네. 고비 좀 넘겼다고 어떻게 이렇게 일이 술술 풀리지?","JPN":"変だな。ここ最近、何もかも上手くいきすぎてる。","ENG":"Interesting. I just went through a rough patch, but I didn't expect things to work out this well afterward.","TWN":"真奇怪……好不容易熬過了難關，事情就變得這麼順利了？"},"stage":{"bg":"DORMITORY_3","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SPEAKER_DEBT_NECK_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L24_1","type":"dialog","speaker":"SPEAKER_DEBT_NECK_NULL","text":{"KOREA":"고생 끝에 낙이 찾아온다더니… 이제야 겨우 나한테도 볕 들 날이 찾아오는구나.","JPN":"苦労の先には幸運が待つっていうけど……ついに私にも光が差したんだ。","ENG":"Well, I guess it's a reward for all the suffering I went through... Finally, things are looking up.","TWN":"苦盡甘來……終於輪到我也迎來光明的日子了。"},"stage":{"bg":"DORMITORY_3","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SPEAKER_DEBT_NECK_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L26_1","type":"dialog","speaker":"SPEAKER_DEBT_NECK_NULL","text":{"KOREA":"네. 잠시만요~.","JPN":"はい、今行きます～。","ENG":"Yes, coming!","TWN":"等一下，來了～"},"stage":{"bg":"DORMITORY_3","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SPEAKER_DEBT_NECK_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L29_1","type":"dialog","speaker":"SPEAKER_DEBT_NECK_NULL","text":{"KOREA":"먼 길 오느라 고생 많으셨습니다. 그러니까-","JPN":"遥々遠方からお越しいただきありがとうございます。えっと―","ENG":"Thank you for coming all the way he–","TWN":"大老遠地跑過來辛苦…"},"stage":{"bg":"DEBT_04","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L30_1","type":"dialog","speaker":"SPEAKER_DEBT_NECK_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"DEBT_04","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L32_1","type":"dialog","speaker":"RIBBON_DEBT_NECK_NULL","text":{"KOREA":"썩 안내하지 못할까, 어이-.","JPN":"はやく案内しろ、コラ。","ENG":"Lead the way. Arr.","TWN":"怎麼還不帶路？"},"stage":{"bg":"DEBT_04","bgm":"UI_SPORT_RACE_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L34_1","type":"dialog","speaker":"SPEAKER_DEBT_NECK_NULL","text":{"KOREA":"허억… 허억…….","JPN":"はあ……はあ……","ENG":"*Huff* *Huff*","TWN":"呼……呼……"},"stage":{"bg":"DORMITORY_3","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SPEAKER_DEBT_NECK_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L35_1","type":"dialog","speaker":"SPEAKER_DEBT_NECK_NULL","text":{"KOREA":"시, 심장아… 내가 방금 뭘 본 거지?","JPN":"び、びっくりした……今の何？","ENG":"W-what...? Did I just see who I thought I saw?","TWN":"我，我的心臟……我剛才看到了什麼？"},"stage":{"bg":"DORMITORY_3","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SPEAKER_DEBT_NECK_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L36_1","type":"dialog","speaker":"SPEAKER_DEBT_NECK_NULL","text":{"KOREA":"그래. 분명 잘못 본 걸 거야. 아무렴. 피곤한 나머지 헛것을 본 게 분명해.","JPN":"きっと見間違いだよね。うんうん、疲労で幻覚が見えたに決まってる。","ENG":"No, I must be wrong. Yeah. I'm just tired so I'm seeing things.","TWN":"對，一定是看錯了。沒錯。肯定是太累了，產生了幻覺。"},"stage":{"bg":"DORMITORY_3","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SPEAKER_DEBT_NECK_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L37_1","type":"dialog","speaker":"SPEAKER_DEBT_NECK_NULL","text":{"KOREA":"나도 참. 헛것에 홀려 손님분께 민폐를 끼치다니. 이럼 안 돼, 유피.","JPN":"そうだよ、幻覚が見えたからって、お客様に失礼な態度をとっちゃダメじゃない、ユピ。","ENG":"Come on, Yuppie. Get it together. You can't be rude to a guest just because you're seeing things.","TWN":"我也真是，被幻覺嚇到，給客人添了麻煩。這樣可不行，悠菲。"},"stage":{"bg":"DORMITORY_3","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SPEAKER_DEBT_NECK_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L40_1","type":"dialog","speaker":"SPEAKER_DEBT_NECK_NULL","text":{"KOREA":"죄송합니다~. 제가 잠시 헛것을 보는 바람에.","JPN":"すみません、ちょっと幻覚が見えてしまいまして。","ENG":"I'm sorry! I was mistaken.","TWN":"對不起！我剛才好像看錯了。"},"stage":{"bg":"DEBT_04","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L41_1","type":"dialog","speaker":"RIBBON_DEBT_NECK_NULL","text":{"KOREA":"괜찮습니다. 크레데레가 이세상 귀여움이 아니긴 하죠.","JPN":"大丈夫ですよ。クレデレのあまりの可愛さに、幻覚を疑うのも仕方ありません。","ENG":"It is all right. Credere's adorable face often distracts people.","TWN":"沒關係，因為克蕾妲莉可愛到簡直不像是這個世界的。"},"stage":{"bg":"DEBT_04","bgm":"UI_SPORT_RACE_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L42_1","type":"dialog","speaker":"SPEAKER_DEBT_NECK_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"DEBT_04","bgm":"UI_SPORT_RACE_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L43_1","type":"dialog","speaker":"RIBBON_DEBT_NECK_NULL","text":{"KOREA":"아무리 크레데레라도 그렇게 빤히 쳐다보면 부끄러워요.","JPN":"ちょっと、いくらクレデレでもそんなに見つめられたらちょっと照れます。","ENG":"Credere is going to get embarrassed if you keep staring at her like this.","TWN":"就算是克蕾妲莉，這樣被盯著看也會害羞的。"},"stage":{"bg":"DEBT_04","bgm":"UI_SPORT_RACE_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L45_1","type":"dialog","speaker":"SPEAKER_DEBT_NECK_NULL","text":{"KOREA":"으아아아아아아악-!!","JPN":"うわあああああああ！！","ENG":"AHHHHHHHHHH!","TWN":"啊啊啊啊啊啊啊——！！"},"stage":{"bg":"DEBT_04","bgm":"UI_SPORT_RACE_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}},"sfx":"FX_COMBAT_ALL_FOOT_STEP_LANDING_BIG_02"},{"id":"L46_1","type":"dialog","speaker":"SPEAKER_DEBT_NECK_NULL","text":{"KOREA":"네가, 네가 왜 여기 있는 거야!","JPN":"な、なんであなたがここにいるんです！？","ENG":"W-what are you doing here?!","TWN":"你、你為什麼會在這裡！"},"stage":{"bg":"DEBT_04","bgm":"UI_SPORT_RACE_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L47_1","type":"dialog","speaker":"RIBBON_DEBT_NECK_NULL","text":{"KOREA":"무얼 숨기랴. 크레데레는 최근 놀라운 활약으로 용감한 시민상을 수상하였습니다.","JPN":"何を隠そう、クレデレは昨今の凄まじい活躍によって勇敢な市民賞を受賞したのです。","ENG":"No skeletons in this closet. Credere recently received the medal of bravery for her astonishing achievements.","TWN":"克蕾妲莉沒有祕密。克蕾妲莉最近因為驚人的表現獲得勇敢市民獎。"},"stage":{"bg":"DEBT_04","bgm":"UI_SPORT_RACE_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L48_1","type":"dialog","speaker":"RIBBON_DEBT_NECK_NULL","text":{"KOREA":"덕분에 아빠에게 인정받아 독립을 허락받았죠.","JPN":"そのおかげで、お父さんから許しを得て独立したんです。","ENG":"That was enough for her father to allow her to move out.","TWN":"多虧了你，爸爸才認可了克蕾妲莉，允許克蕾妲莉獨立了。"},"stage":{"bg":"DEBT_04","bgm":"UI_SPORT_RACE_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L49_1","type":"dialog","speaker":"SPEAKER_DEBT_NECK_NULL","text":{"KOREA":"그러니까 그게 여기 있는 거랑 무슨 상관이냐고!","JPN":"それはここにいる説明になっていません！","ENG":"What does that have to do with you showing up at this doorstep?!","TWN":"那和你在這裡有什麼關係？"},"stage":{"bg":"DEBT_04","bgm":"UI_SPORT_RACE_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L50_1","type":"dialog","speaker":"RIBBON_DEBT_NECK_NULL","text":{"KOREA":"전에 크레데레가 유피의 과자를 팔아먹겠다고 말하지 않았나요.","JPN":"以前、クレデレはユピのお菓子を売ってお金を稼ぐと言いましたよね。","ENG":"Didn't Credere mention how she was going to make a business out of Yuppie's snacks?","TWN":"之前克蕾妲莉不是說要賣悠菲的點心嗎？"},"stage":{"bg":"DEBT_04","bgm":"UI_SPORT_RACE_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L1_1","type":"dialog","speaker":"RIBBON_DEBT_NECK_NULL","text":{"KOREA":"어떻게 하면 유피의 도움을 얻을 수 있을까 생각하던 와중, 크레데레는 깨달았습니다.","JPN":"どうしたらユピに協力してもらえるか考えていたのですが、クレデレは思いついたんです。","ENG":"Credere was wondering how she could get Yuppie to help, and then realized.","TWN":"在想著如何讓悠菲答應的時候，克蕾妲莉突然明白了。"},"stage":{"bg":"DEBT_04","bgm":"UI_SPORT_RACE_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L2_1","type":"dialog","speaker":"RIBBON_DEBT_NECK_NULL","text":{"KOREA":"보육원을 차지하면, 놀라워라. 유피를 마음대로 부려먹을 수 있다는 사실.","JPN":"孤児院を買っちゃえば、あらびっくり。ユピを好きなようにこき使えるなと。","ENG":"Credere can gain ownership of the orphanage and she'll be able to order Yuppie around.","TWN":"佔領育幼院，就可以隨心所欲地使喚悠菲囉！"},"stage":{"bg":"DEBT_04","bgm":"UI_SPORT_RACE_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L3_1","type":"dialog","speaker":"SPEAKER_DEBT_NECK_NULL","text":{"KOREA":"거, 거짓말.","JPN":"う、うそぉ。","ENG":"N-no way.","TWN":"這，這不是真的。"},"stage":{"bg":"DEBT_04","bgm":"UI_SPORT_RACE_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L4_1","type":"dialog","speaker":"SPEAKER_DEBT_NECK_NULL","text":{"KOREA":"그런 거짓말은 하지도 마… 질 나쁜 농담은 하는 게 아니라고…….","JPN":"冗談きついよ……嘘だって言って……","ENG":"Stop it... You shouldn't lie about things like that...","TWN":"騙人……不要開這種惡劣的玩笑……"},"stage":{"bg":"DEBT_04","bgm":"UI_SPORT_RACE_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L5_1","type":"dialog","speaker":"RIBBON_DEBT_NECK_NULL","text":{"KOREA":"받아들이시죠, 유피.","JPN":"受け入れてください、ユピ。","ENG":"Just accept it, Yuppie.","TWN":"接受吧，悠菲。"},"stage":{"bg":"DEBT_04","bgm":"UI_SPORT_RACE_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L6_1","type":"dialog","speaker":"RIBBON_DEBT_NECK_NULL","text":{"KOREA":"지금 이 순간부터.","JPN":"今、この瞬間から……","ENG":"From this moment on.","TWN":"從這一刻開始。"},"stage":{"bg":"DEBT_04","bgm":"UI_SPORT_RACE_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}},"sfx":"FX_CUTSCEN_TADA2"},{"id":"L7_1","type":"dialog","speaker":"RIBBON_DEBT_NECK_NULL","text":{"KOREA":"우린 영원한 운명공동체예요.","JPN":"私たちは未来永劫、運命共同体になったのです。","ENG":"We are forever together.","TWN":"我們就是永遠的命運共同體了。"},"stage":{"bg":"DEBT_04","bgm":"UI_SPORT_RACE_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}},"sfx":"FX_CUTSCEN_TADA2"},{"id":"L8_1","type":"dialog","speaker":"SPEAKER_DEBT_NECK_NULL","text":{"KOREA":"으… 으으…….","JPN":"う、うう……！","ENG":"Agh... Egh...","TWN":"呃……呃呃……"},"stage":{"bg":"DEBT_04","bgm":"UI_SPORT_RACE_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L9_1","type":"dialog","speaker":"RIBBON_DEBT_NECK_NULL","text":{"KOREA":"너무 기뻐서 말이 안 나오나 보군요. 심정은 이해합니다.","JPN":"嬉しすぎて言葉を失ったんですね。その気持ちはよくわかります。","ENG":"It seems like you are too jubilant to speak. Credere understands.","TWN":"你一定是高興到說不出話來吧。克蕾妲莉能夠理解你的心情。"},"stage":{"bg":"DEBT_04","bgm":"UI_SPORT_RACE_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L10_1","type":"dialog","speaker":"RIBBON_DEBT_NECK_NULL","text":{"KOREA":"여기 집들이 선물을 준비했으니 받으시길.","JPN":"どうぞ。お土産を持ってきました。","ENG":"Here is a housewarming gift. Take it.","TWN":"這裡準備了一些喬遷禮物，請收下吧。"},"stage":{"bg":"DEBT_04","bgm":"UI_SPORT_RACE_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L11_1","type":"dialog","speaker":"SPEAKER_DEBT_NECK_NULL","text":{"KOREA":"이건…?","JPN":"これは……？","ENG":"Is this…?","TWN":"這是……？"},"stage":{"bg":"DEBT_04","bgm":"UI_SPORT_RACE_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L12_1","type":"dialog","speaker":"RIBBON_DEBT_NECK_NULL","text":{"KOREA":"무얼 숨기랴. 새롭게 리뉴얼된 크레데레의 칭찬도장입니다.","JPN":"何を隠そう、新しく改良されたクレデレのよくできましたステッカーです。","ENG":"No skeletons in this closet. This is Credere's renewed stamps.","TWN":"克蕾妲莉沒有祕密。這是全新改版後的克蕾妲莉好寶寶印章。"},"stage":{"bg":"DEBT_04","bgm":"UI_SPORT_RACE_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L13_1","type":"dialog","speaker":"RIBBON_DEBT_NECK_NULL","text":{"KOREA":"30장을 모으면, 놀라워라. 귀여운 크레데레가 한 번 안아드린답니다.","JPN":"30個集めたら、ビックリ仰天。可愛いクレデレが一度だけ抱きしめて差し上げます。","ENG":"Get 30 stamps, and, surprise, surprise. You can get a big hug from the adorable Credere.","TWN":"集齊30個，期待吧！可愛的克蕾妲莉會給你一個擁抱喔。"},"stage":{"bg":"DEBT_04","bgm":"UI_SPORT_RACE_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L14_1","type":"dialog","speaker":"SPEAKER_DEBT_NECK_NULL","text":{"KOREA":"으… 으으…….","JPN":"う、うう……！","ENG":"Agh... Eghhhh...","TWN":"呃……呃呃……"},"stage":{"bg":"DEBT_04","bgm":"UI_SPORT_RACE_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L15_1","type":"dialog","speaker":"SPEAKER_DEBT_NECK_NULL","text":{"KOREA":"으아아아아악──!!!","JPN":"うあああああああ！！","ENG":"AHHHHHHHHHH!","TWN":"呃啊啊啊啊啊──!!!"},"stage":{"bg":"DEBT_04","bgm":"UI_SPORT_RACE_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}},"sfx":"FX_CUTSCEN_NOISE_FIGHT"},{"id":"L18_1","type":"narration","speaker":null,"text":{"KOREA":"이리하야! 길었던 시그마 해적단의 모험은 막을 내리니!","JPN":"こうして、長きにわたるシグマ海賊団の冒険は幕を下ろしたのである！","ENG":"And thus! The long tale of the Sigma Pirates comes to an end!","TWN":"就這樣！西格瑪海盜團漫長的冒險終於落幕！"},"stage":{"bg":"DEBT_04","bgm":"THEMA_CA_SIGMA_02","filter":"NCFT_SEPIA","slots":{"L":null,"C":null,"R":null}}},{"id":"L19_1","type":"narration","speaker":null,"text":{"KOREA":"조금 티격태격해도 유피와 크레데레는 잘 지내고 있어.","JPN":"揉めがちだけど、ユピとクレデレは一緒にうまくやっている。","ENG":"Yuppie and Credere bicker, but they are doing well.","TWN":"雖然有點小爭吵，但悠菲和克蕾妲莉相處得很好。"},"stage":{"bg":"DEBT_04","bgm":"THEMA_CA_SIGMA_02","filter":"NCFT_SEPIA","slots":{"L":null,"C":null,"R":null}}},{"id":"L20_1","type":"narration","speaker":null,"text":{"KOREA":"최근에는 크레데레의 가족이 보육원에 놀러왔다나 봐!","JPN":"最近、クレデレの家族が孤児院に遊びに来たんだって！","ENG":"I also heard Credere's family visited the orphanage, too!","TWN":"最近克蕾妲莉的家人好像也去育幼院玩了！"},"stage":{"bg":"DEBT_04","bgm":"THEMA_CA_SIGMA_02","filter":"NCFT_SEPIA","slots":{"L":null,"C":null,"R":null}}},{"id":"L22_1","type":"narration","speaker":null,"text":{"KOREA":"아, 맞다. 그러고 보니 알파트릭스 기밀 유출범도 무사히 잡았었지?","JPN":"あ、そうだ。そういえばアルファトリックス機密情報の漏洩犯も掴まったらしい。","ENG":"Oh, and the person who leaked Alphatrix's secret was caught, too!","TWN":"啊，對了。說起來，阿爾法崔克斯的洩密犯也順利抓到了！"},"stage":{"bg":"MYEONGDONG","bgm":"THEMA_CA_SIGMA_02","filter":"NCFT_SEPIA","slots":{"L":null,"C":null,"R":null}}},{"id":"L23_1","type":"narration","speaker":null,"text":{"KOREA":"듣기로는 크레데레가 엄청난 활약을 했대!","JPN":"聞くところによると、クレデレが大活躍をしたそうだ！","ENG":"Apparently, Credere played a big role in the whole thing!","TWN":"聽說克蕾妲莉表現得非常出色！"},"stage":{"bg":"MYEONGDONG","bgm":"THEMA_CA_SIGMA_02","filter":"NCFT_SEPIA","slots":{"L":null,"C":null,"R":null}}},{"id":"L24_1","type":"dialog","speaker":"MAN_NPC_GEASS_NULL","text":{"KOREA":"대체… 내가 범인이란 걸 어떻게 안 거지?","JPN":"いったい……どうやって私を突き止めた？","ENG":"How... How did you find out I was behind it?","TWN":"到底……是怎麼知道我的？"},"stage":{"bg":"MYEONGDONG","bgm":"THEMA_CA_SIGMA_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}},"sfx":"FX_COMBAT_ALL_MAGIC_SPELL_LIGHT_02"},{"id":"L25_1","type":"dialog","speaker":"MAN_NPC_GEASS_NULL","text":{"KOREA":"메모리카드의 사본이 있었다는 사실도 모르고 있었을 텐데!","JPN":"メモリカードのコピーがあることも知らなかったんだろう！","ENG":"You probably didn't even know there was a copy of the memory card!","TWN":"你們根本不知道記憶卡還有副本存在吧！"},"stage":{"bg":"MYEONGDONG","bgm":"THEMA_CA_SIGMA_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L26_1","type":"dialog","speaker":"RIBBON_DEBT_NECK_NULL","text":{"KOREA":"무얼 숨기랴. 우연입니다.","JPN":"何を隠そう、たまたまです。","ENG":"No skeletons in this closet. It was a coincidence.","TWN":"克蕾妲莉沒有祕密，這只是巧合。"},"stage":{"bg":"MYEONGDONG","bgm":"THEMA_CA_SIGMA_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RIBBON_DEBT_NECK_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L28_1","type":"dialog","speaker":"SPEAR_ALPHA_NULL_SHORT","text":{"KOREA":"뭐야, 우연이었구나?","JPN":"なんだ、たまたまだったか？","ENG":"Oh, it was a coincidence.","TWN":"什麼啊，原來是巧合？"},"stage":{"bg":"MYEONGDONG","bgm":"THEMA_CA_SIGMA_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SPEAR_ALPHA_NULL_SHORT","face":"UNIT_LAUGH"},"C":null,"R":null}}},{"id":"L29_1","type":"dialog","speaker":"CHOI_ALPHA_NULL_SHORT","text":{"KOREA":"음. 우연이라면 어쩔 수 없지.","JPN":"それなら、納得だ。","ENG":"Mm. Not much you can do about coincidences.","TWN":"嗯。既然是巧合，那也沒辦法了。"},"stage":{"bg":"MYEONGDONG","bgm":"THEMA_CA_SIGMA_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SPEAR_ALPHA_NULL_SHORT","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"CHOI_ALPHA_NULL_SHORT","face":"UNIT_PRIDE"}}}},{"id":"L31_1","type":"dialog","speaker":"MAN_NPC_GEASS_NULL","text":{"KOREA":"젠장! 이런 멍청이들에게 몰리다니!!","JPN":"ちくしょー！　こんなアホどもに追い詰められるなんて！！","ENG":"Damn it! I can't believe these idiots got me!","TWN":"可惡！竟然被這些笨蛋逼到這種地步！！"},"stage":{"bg":"MYEONGDONG","bgm":"THEMA_CA_SIGMA_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SPEAR_ALPHA_NULL_SHORT","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"CHOI_ALPHA_NULL_SHORT","face":"UNIT_IDLE"}}}},{"id":"L32_1","type":"dialog","speaker":"MAN_NPC_GEASS_NULL","text":{"KOREA":"이렇게 된 이상… 이곳에서 알파트릭스의 기밀을 퍼트려주마!","JPN":"こうなった以上……今この場でアルファトリックスの機密をばらまいてやる！","ENG":"Now... I have no choice but to leak Alphatrix's secrets right here!","TWN":"既然如此……就在這裡把阿爾法崔克斯的機密公之於眾吧！"},"stage":{"bg":"MYEONGDONG","bgm":"THEMA_CA_SIGMA_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SPEAR_ALPHA_NULL_SHORT","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"CHOI_ALPHA_NULL_SHORT","face":"UNIT_IDLE"}}}},{"id":"L34_1","type":"dialog","speaker":null,"text":{"KOREA":"<color=#ffd34c>음흐흐… 라면을~ 맛있게 먹는 방법~.</color>","JPN":"<color=#ffd34c>ぬふふ……ラーメンの美味しい食べ方とは……</color>","ENG":"<color=#ffd34c>He he he... How to make instant noodles taste better!</color>","TWN":"<color=#ffd34c>嗯哼哼……吃泡面的～美味方法～</color>"},"stage":{"bg":"MYEONGDONG","bgm":"THEMA_CA_SIGMA_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L35_1","type":"dialog","speaker":null,"text":{"KOREA":"<color=#ffd34c>스텐냄비에~ 평소보다 물을 많이 넣고~.</color>","JPN":"<color=#ffd34c>ステンレス製鍋に水を少し多めに入れて……</color>","ENG":"<color=#ffd34c>Get a stainless steel pot! Put a little more water in than usual!</color>","TWN":"<color=#ffd34c>在不銹鋼鍋裡～比平時多加點水～</color>"},"stage":{"bg":"MYEONGDONG","bgm":"THEMA_CA_SIGMA_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L36_1","type":"dialog","speaker":null,"text":{"KOREA":"<color=#ffd34c>스프를 조금 덜 넣어주고 보글보글 푹 끓여주면~</color>","JPN":"<color=#ffd34c>粉末スープは少なめ、そしてお沸騰するまで待つ。</color>","ENG":"<color=#ffd34c>Put a little less of the flavoring packets! Let it boil!</color>","TWN":"<color=#ffd34c>少放點調味料包，然後煮得滾燙滾燙～</color>"},"stage":{"bg":"MYEONGDONG","bgm":"THEMA_CA_SIGMA_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L37_1","type":"dialog","speaker":null,"text":{"KOREA":"<color=#ffd34c>맛있는 순한 맛 라면이- 쨘!</color>","JPN":"<color=#ffd34c>じゃじゃーん！　美味しい薄味ラーメンの完成！</color>","ENG":"<color=#ffd34c>Tada! You get delicious, mild-flavored noodles!</color>","TWN":"<color=#ffd34c>美味的清淡拉麵，上桌囉～！</color>"},"stage":{"bg":"MYEONGDONG","bgm":"THEMA_CA_SIGMA_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L38_1","type":"dialog","speaker":"MAN_NPC_GEASS_NULL","text":{"KOREA":"……응?","JPN":"……あれ？","ENG":"...Hmm?","TWN":"……呃？"},"stage":{"bg":"MYEONGDONG","bgm":"THEMA_CA_SIGMA_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L39_1","type":"dialog","speaker":"SPEAR_ALPHA_NULL_SHORT","text":{"KOREA":"아아……!","JPN":"ああ……！","ENG":"Ah...!","TWN":"哎呀……！"},"stage":{"bg":"MYEONGDONG","bgm":"THEMA_CA_SIGMA_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SPEAR_ALPHA_NULL_SHORT","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L41_1","type":"dialog","speaker":"SPEAR_ALPHA_NULL_SHORT","text":{"KOREA":"결국 알아버렸구나. 내가 고심해서 만든 비장의 순한 맛 라면 레시피를!","JPN":"ついに知られてしまったのね。私が苦労して編み出した薄味ラーメンのレシピが！","ENG":"Now it's out in the open. My secret mild-flavored noodles recipe that I worked so hard to figure out!","TWN":"被發現了，我精心烹飪的獨門溫和口味泡麵食譜！"},"stage":{"bg":"MYEONGDONG","bgm":"THEMA_CA_SIGMA_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SPEAR_ALPHA_NULL_SHORT","face":"UNIT_HATE"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_02"},{"id":"L43_1","type":"dialog","speaker":"MAN_NPC_GEASS_NULL","text":{"KOREA":"화낼 사람은 나지! 대체 이딴 걸 왜 기밀파일에 보관하는 거야?","JPN":"ああ……って言いたいのはこっちだ！　なんでこんなものを機密ファイルに入れるんだ！","ENG":"I'm the one who should be angry! Why would this be categorized as a secret?!","TWN":"該生氣的人是我吧！到底為什麼要把這種東西保存在機密檔裡？"},"stage":{"bg":"MYEONGDONG","bgm":"THEMA_CA_SIGMA_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SPEAR_ALPHA_NULL_SHORT","face":"UNIT_IDLE"},"R":null}}},{"id":"L44_1","type":"dialog","speaker":"CHOI_ALPHA_NULL_SHORT","text":{"KOREA":"이건 다음 달 이루어질 모 식품업체와의 깜짝 콜라보 CM송.","JPN":"これは来月撮影予定の某食品会社との極秘コラボで使うCMソングだ。","ENG":"This was the surprise collaboration song for an ad that was going to be released next month.","TWN":"這是下個月將與某個食品公司進行的驚喜合作廣告歌曲。"},"stage":{"bg":"MYEONGDONG","bgm":"THEMA_CA_SIGMA_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CHOI_ALPHA_NULL_SHORT","face":"UNIT_IDLE"},"R":null}}},{"id":"L45_1","type":"dialog","speaker":"CHOI_ALPHA_NULL_SHORT","text":{"KOREA":"아직 발표가 안됐으니 기밀로 관리하는 건 당연하다.","JPN":"まだ公開前の、れっきとした機密情報だぞ。","ENG":"Of course it's a secret since it has not been announced yet.","TWN":"因為還沒有發佈，所以當然要作為機密保管。"},"stage":{"bg":"MYEONGDONG","bgm":"THEMA_CA_SIGMA_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CHOI_ALPHA_NULL_SHORT","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L47_1","type":"dialog","speaker":"RIBBON_DEBT_NECK_NULL","text":{"KOREA":"그리고 이건 라면 가루를 섞어 만든 최루탄입니다.","JPN":"そして、これはラーメンの粉末スープで作った催涙弾です。","ENG":"And this is a tear bomb Credere made using the flavoring packet.","TWN":"這個是用麵粉混合製成的催淚彈。"},"stage":{"bg":"MYEONGDONG","bgm":"THEMA_CA_SIGMA_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RIBBON_DEBT_NECK_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L48_1","type":"dialog","speaker":"RIBBON_DEBT_NECK_NULL","text":{"KOREA":"그야말로 미스터 쮸빕에 안성맞춤인 매콤한 콜라보 제품이라 할 수 있죠.","JPN":"まさにミスター・チュピーの弾薬としてぴったりなコラボ製品といえます。","ENG":"It is a spicy collaboration product that is perfect for Mr. Squirty.","TWN":"可以說是非常適合咻咻先生的辛辣合作產品。"},"stage":{"bg":"MYEONGDONG","bgm":"THEMA_CA_SIGMA_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RIBBON_DEBT_NECK_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L50_1","type":"dialog","speaker":"MAN_NPC_GEASS_NULL","text":{"KOREA":"우… 웃기지 마.","JPN":"ふ、ふざけるな。","ENG":"D-don't be absurd.","TWN":"開……開什麼玩笑。"},"stage":{"bg":"MYEONGDONG","bgm":"THEMA_CA_SIGMA_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RIBBON_DEBT_NECK_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L1_1","type":"dialog","speaker":"MAN_NPC_GEASS_NULL","text":{"KOREA":"이딴 어처구니없는 일로 잡혀갈 것 같냐아아아-!!","JPN":"こんなくだらないことで、捕まってたまるか！！","ENG":"I don't want to be sent to jail for something like thiiiiiiiis!","TWN":"你以為我會因為這種荒謬的事被抓走嗎！！！"},"stage":{"bg":"MYEONGDONG","bgm":"THEMA_CA_SIGMA_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RIBBON_DEBT_NECK_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L4_1","type":"dialog","speaker":"MAN_NPC_GEASS_NULL","text":{"KOREA":"어?","JPN":"え？","ENG":"Huh?","TWN":"啊？"},"stage":{"bg":"PRISON_NIGHT_02","bgm":"THEMA_CA_SIGMA_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L5_1","type":"dialog","speaker":"ROGER_DEBT_NPC_NULL","text":{"KOREA":"어서 오십시오, 무슈. G1 보안교육대에 오신 걸 환영합니다.","JPN":"ようこそ、ムッシュ。G1 保安教育隊は君を歓迎する。","ENG":"Bonjour, monsieur. Welcome to the G1 Security Education Center.","TWN":"先生你好。歡迎來到G1安全教育中心。"},"stage":{"bg":"PRISON_NIGHT_02","bgm":"THEMA_CA_SIGMA_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ROGER_DEBT_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L6_1","type":"dialog","speaker":"ROGER_DEBT_NPC_NULL","text":{"KOREA":"혹여 억울하다고 사연풀이 할 생각이라면 꿈도 꾸지 마시길.","JPN":"もし同情を買うつもりで過去エピソードを話すつもりなら、通じないからやめておけと言っておこう。","ENG":"I'd kindly advise you against telling me your backstory.","TWN":"如果你覺得委屈，想要訴說的話，勸你還是少作夢。"},"stage":{"bg":"PRISON_NIGHT_02","bgm":"THEMA_CA_SIGMA_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ROGER_DEBT_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L7_1","type":"narration","speaker":null,"text":{"KOREA":"로저 아저씨는 사건이 정리된 뒤에 감옥으로 돌아갔대.","JPN":"ロジャーのおじさんは事件収束後、刑務所に戻ったんだって。","ENG":"I heard that Roger went back to prison after things were resolved.","TWN":"羅杰叔叔在事件結束後回到了監獄。"},"stage":{"bg":"PRISON_NIGHT_02","bgm":"THEMA_CA_SIGMA_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ROGER_DEBT_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L8_1","type":"narration","speaker":null,"text":{"KOREA":"유피랑 친한 친구인 것 같은데, 빨리 둘이 다시 만났으면 좋겠다!","JPN":"ユピとは仲がいいみたいだったし、はやく二人が再会できるといいな！","ENG":"He seemed to be a close friend of Yuppie, so I hope they meet again soon!","TWN":"他好像是悠菲的好朋友，真希望他們能早點再見面！"},"stage":{"bg":"PRISON_NIGHT_02","bgm":"THEMA_CA_SIGMA_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ROGER_DEBT_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L10_1","type":"dialog","speaker":"ROGER_DEBT_NPC_NULL","text":{"KOREA":"그나저나 출소까지 앞으로 3달입니까…….","JPN":"しかし、出所まであと3カ月ですか……","ENG":"Three months until I finish my sentence...","TWN":"話說距離出獄還有3個月……"},"stage":{"bg":"PRISON_NIGHT_02","bgm":"THEMA_CA_SIGMA_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ROGER_DEBT_NPC_NULL","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_02"},{"id":"L11_1","type":"dialog","speaker":"ROGER_DEBT_NPC_NULL","text":{"KOREA":"후후. 조금만 기다리십시오, 마드모아젤.","JPN":"ふふ、もう少し待っていてくださいね、マドモアゼル。","ENG":"Ha ha. Just you wait, mademoiselle.","TWN":"呵呵。請稍等片刻，小姐。"},"stage":{"bg":"PRISON_NIGHT_02","bgm":"THEMA_CA_SIGMA_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ROGER_DEBT_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L12_1","type":"dialog","speaker":"ROGER_DEBT_NPC_NULL","text":{"KOREA":"반드시… 반드시 이번 일에 대한 대가를 치르게 될 겁니다!","JPN":"必ず……必ずこの借りは返させてもらいます！","ENG":"You will pay for what you did...!","TWN":"我……一定要讓你們為這次的事情付出代價！"},"stage":{"bg":"PRISON_NIGHT_02","bgm":"THEMA_CA_SIGMA_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ROGER_DEBT_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L14_1","type":"narration","speaker":null,"text":{"KOREA":"그러고 보니, 모네 선원은 최근 강력한 불꽃 괴물과의 싸움으로 배탈이 났다나 봐.","JPN":"そういえばモネ船員は、最近、炎の怪物と戦ってお腹を下したらしい。","ENG":"I also heard that Mone had a stomachache from fighting a mighty flame monster.","TWN":"說起來，莫妮船員最近因為與強大的火焰怪物戰鬥而暈船了。"},"stage":{"bg":"VILLAGE1","bgm":"THEMA_CA_SIGMA_02","filter":"NCFT_SEPIA","slots":{"L":null,"C":null,"R":null}}},{"id":"L15_1","type":"narration","speaker":null,"text":{"KOREA":"모네 선원이 고전하다니… 대체 어떤 괴물이었던 걸까?","JPN":"モネ船員が苦戦するなんて……いったいどんな怪物だったのだろう？","ENG":"What kind of monster could make Mone struggle like that...?","TWN":"竟然會讓莫妮船員陷入苦戰……到底是什麼怪物呢？"},"stage":{"bg":"VILLAGE1","bgm":"THEMA_CA_SIGMA_02","filter":"NCFT_SEPIA","slots":{"L":null,"C":null,"R":null}}},{"id":"L16_1","type":"dialog","speaker":"TONFA_FLORA_SUMMER_NULL","text":{"KOREA":"릴리 선배, 도와주는 검다! 이건, 이건 음식이 아니지 말임다!","JPN":"リリー先輩、助けてくださいっす！　これは、食べ物ではないっす！","ENG":"Lily, help! Th-this isn't edible at all!","TWN":"莉莉前輩，幫幫忙！這、這根本不是人吃的唄！"},"stage":{"bg":"VILLAGE1","bgm":"THEMA_CA_SIGMA_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"TONFA_FLORA_SUMMER_NULL","face":"UNIT_SURPRISE"},"R":null}},"sfx":"FX_COMBAT_ALL_MAGIC_SPELL_LIGHT_02"},{"id":"L19_1","type":"dialog","speaker":"SPEAR_FLORA_SUMMER_NULL","text":{"KOREA":"야. 원래 몸에 좋은 게 입에는 쓴 거야.","JPN":"良薬は口に苦しって言うでしょ？","ENG":"Hey. Don't be a picky eater.","TWN":"喂，良藥苦口。"},"stage":{"bg":"VILLAGE1","bgm":"THEMA_CA_SIGMA_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MASK_FLORA_SUMMER_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SPEAR_FLORA_SUMMER_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L20_1","type":"dialog","speaker":"SPEAR_FLORA_SUMMER_NULL","text":{"KOREA":"내가 영양성분 고려하느라 얼마나 애 먹었는 줄 알아?","JPN":"しっかり栄養を考えて、苦労して作ったんだからね。","ENG":"Do you know how much thought I put into balancing the nutritional values?","TWN":"你知道我為了考慮營養搭配費了多少心思嗎？"},"stage":{"bg":"VILLAGE1","bgm":"THEMA_CA_SIGMA_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MASK_FLORA_SUMMER_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SPEAR_FLORA_SUMMER_NULL","face":"UNIT_HATE"}}}},{"id":"L21_1","type":"dialog","speaker":"MASK_FLORA_SUMMER_NULL","text":{"KOREA":"먹고 죽은 귀신이 때깔도 고운 법입니다. 참고 견디세요.","JPN":"空腹で死ぬより、お腹いっぱいで死んだほうがマシでしょう。だから我慢してください。","ENG":"If you're going out, you might as well go out eating.","TWN":"吃飽總比餓死好，忍耐一下吧。"},"stage":{"bg":"VILLAGE1","bgm":"THEMA_CA_SIGMA_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MASK_FLORA_SUMMER_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SPEAR_FLORA_SUMMER_NULL","face":"UNIT_HATE"}}}},{"id":"L23_1","type":"dialog","speaker":"TONFA_FLORA_SUMMER_NULL","text":{"KOREA":"비유가 뭔가 이상하지 말임다?!","JPN":"そのたとえはおかしくないっすか！？","ENG":"What do you mean?!","TWN":"好像哪裡怪怪的？！"},"stage":{"bg":"VILLAGE1","bgm":"THEMA_CA_SIGMA_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"TONFA_FLORA_SUMMER_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L25_1","type":"narration","speaker":null,"text":{"KOREA":"다음은 에리어스 선원! 크레데레를 도와줘서 고맙다고 유피가 과자를 선물했었지?","JPN":"次はエリウス船員！　クレデレを助けてくれたお礼にユピがお菓子をプレゼントしたんだよね。","ENG":"Next is Arius! Yuppie gave her snacks as a thank you for helping Credere!","TWN":"接下來是埃里奧斯船員！悠菲為了感謝她的幫助，送了一些點心給她！"},"stage":{"bg":"FRONTBAY_IN","bgm":"THEMA_CA_SIGMA_02","filter":"NCFT_SEPIA","slots":{"L":null,"C":null,"R":null}}},{"id":"L26_1","type":"narration","speaker":null,"text":{"KOREA":"기사단 언니들이랑 다 같이 먹는다고 했는데, 맛있게 먹었으면 좋겠다!","JPN":"騎士団のお姉ちゃんたちと一緒に食べるって言ってたけど、みんなの口に合うといいな！","ENG":"She said she was going to share with the Knights. I hope they all enjoyed it!","TWN":"埃里奧斯說要和騎士團的姊姊們一起吃，希望她們吃得開心！"},"stage":{"bg":"FRONTBAY_IN","bgm":"THEMA_CA_SIGMA_02","filter":"NCFT_SEPIA","slots":{"L":null,"C":null,"R":null}}},{"id":"L27_1","type":"dialog","speaker":"ARIUS_ZODIAC_NULL_NULL","text":{"KOREA":"어라. 여긴 어디죠~? 분명 알려준 대로 왔는데…….","JPN":"あれ？　ここはどこですか？　教えてもらったとおりに来たんだけど……","ENG":"Huh? Where am I? I followed the directions I was given...","TWN":"欸？這裡是哪裡啊～？明明是按照告訴我的路線來的……"},"stage":{"bg":"FRONTBAY_IN","bgm":"THEMA_CA_SIGMA_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ARIUS_ZODIAC_NULL_NULL","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_COMBAT_ALL_MAGIC_SPELL_LIGHT_02"},{"id":"L29_1","type":"dialog","speaker":"TUCKER_FRONTBAY_NULL_NULL","text":{"KOREA":"킥킥. 꼬마 아가씨. 터커 해적단에 흥미라도 있는 거야?","JPN":"くくっ、お嬢ちゃん。ターカー海賊団に興味があるのかい？","ENG":"Ke ke. Hey, little lady. Are you interested in joining the Tucker Pirates?","TWN":"嘿嘿，小丫頭。對塔克海盜團感興趣嗎？"},"stage":{"bg":"FRONTBAY_IN","bgm":"THEMA_CA_SIGMA_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ARIUS_ZODIAC_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"TUCKER_FRONTBAY_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L30_1","type":"dialog","speaker":"ARIUS_ZODIAC_NULL_NULL","text":{"KOREA":"와, 해적이시군요? 저도 시그마 해적단의 선원이에요, 얼!","JPN":"わあ、海賊？　私もシグマ海賊団の船員なんです、ARRR！","ENG":"Wow, you're a pirate? I am a crew mate of the Sigma Pirates too! Yarr!","TWN":"哇，你是海盜嗎？我也是！我是西格瑪海盜團的船員，呀吼！"},"stage":{"bg":"FRONTBAY_IN","bgm":"THEMA_CA_SIGMA_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ARIUS_ZODIAC_NULL_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"TUCKER_FRONTBAY_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L31_1","type":"dialog","speaker":"TUCKER_FRONTBAY_NULL_NULL","text":{"KOREA":"시그마 해적단이라면… 분명 드라코가 말한.","JPN":"シグマ海賊団……確かドラコが言っていたな。","ENG":"Sigma Pirates...? Dracasia said–","TWN":"西格瑪海盜團的話……肯定是德拉克提到的那個。"},"stage":{"bg":"FRONTBAY_IN","bgm":"THEMA_CA_SIGMA_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ARIUS_ZODIAC_NULL_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"TUCKER_FRONTBAY_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L32_1","type":"dialog","speaker":"TUCKER_FRONTBAY_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"FRONTBAY_IN","bgm":"THEMA_CA_SIGMA_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ARIUS_ZODIAC_NULL_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"TUCKER_FRONTBAY_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L33_1","type":"dialog","speaker":null,"text":{"KOREA":"으아아악-! 저번처럼 부두에 묶이기 싫으면 다들 도망쳐!","JPN":"うわああーっ！　あのときみたいに桟橋に縛られたくなければ、皆逃げろ！","ENG":"AHHHHHH! Everyone, run unless you want to be tied at the docks like last time!","TWN":"啊啊啊——！如果不想像上次那樣被綁在碼頭，大家快逃！"},"stage":{"bg":"FRONTBAY_IN","bgm":"THEMA_CA_SIGMA_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}},"sfx":"FX_CUTSCEN_FOOTSTEP_RUNNING_02"},{"id":"L34_1","type":"dialog","speaker":"ARIUS_ZODIAC_NULL_NULL","text":{"KOREA":"앗, 다들 어디 가시는 거죠…?","JPN":"あっ、みなさんどこに行くんですか……？","ENG":"Oh, where is everyone going...?","TWN":"啊，大家都跑哪去了……？"},"stage":{"bg":"FRONTBAY_IN","bgm":"THEMA_CA_SIGMA_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ARIUS_ZODIAC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L38_1","type":"dialog","speaker":"SIGMA_RAS_NULL_NULL","text":{"KOREA":"이렇게 하면… 끝!","JPN":"よしこれで、終わりっと！","ENG":"And... that's it!","TWN":"以上……完畢！"},"stage":{"bg":"TRAINING","bgm":"THEMA_CA_SIGMA_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SIGMA_RAS_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L39_1","type":"dialog","speaker":"SIGMA_RAS_NULL_NULL","text":{"KOREA":"다 했다!","JPN":"完成！","ENG":"I'm done!","TWN":"全都搞定了！"},"stage":{"bg":"TRAINING","bgm":"THEMA_CA_SIGMA_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SIGMA_RAS_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L40_1","type":"dialog","speaker":"TITAN_FAW_NULL_NULL","text":{"KOREA":"오오. 드디어 완성한 건가?","JPN":"おお、ついにか？","ENG":"Ah. Did you finish it?","TWN":"喔喔。終於完成了嗎？"},"stage":{"bg":"TRAINING","bgm":"THEMA_CA_SIGMA_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"TITAN_FAW_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L41_1","type":"dialog","speaker":"TITAN_FAW_NULL_NULL","text":{"KOREA":"이 정도면 사내 연말 행사에서의 수상은 따 놓은 당상이군!","JPN":"これなら社内の忘年会で、入賞すること間違いないだろうな！","ENG":"You are sure to win the award at the year-end company event!","TWN":"以這個程度來看，公司年終活動的獎品根本是囊中之物呢！"},"stage":{"bg":"TRAINING","bgm":"THEMA_CA_SIGMA_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"TITAN_FAW_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L42_1","type":"dialog","speaker":"SIGMA_RAS_NULL_NULL","text":{"KOREA":"음. 시그마 해적단의 여정은 어떤 모험담보다도 굉장하다구?","JPN":"うん、シグマ海賊団の旅はどんな冒険談よりすごいんだよ？","ENG":"Mm. The journey of the Sigma Pirates is greater than any other adventure story out there!","TWN":"嗯。西格瑪海盜團的旅程比任何冒險故事都要精彩喔？"},"stage":{"bg":"TRAINING","bgm":"THEMA_CA_SIGMA_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SIGMA_RAS_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L43_1","type":"dialog","speaker":"SIGMA_RAS_NULL_NULL","text":{"KOREA":"아빠도 재밌게 봐줬으면 좋겠다.","JPN":"パパも楽しんでくれるといいな。","ENG":"I hope Daddy enjoys this, too!","TWN":"希望爸爸也能看得開心。"},"stage":{"bg":"TRAINING","bgm":"THEMA_CA_SIGMA_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SIGMA_RAS_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L44_1","type":"dialog","speaker":"TITAN_FAW_NULL_NULL","text":{"KOREA":"걱정 말게나. 사장은 시그마 얼굴만 봐도 좋아할 테니.","JPN":"安心しな。社長はシグマに会えるだけで喜ぶはずだ。","ENG":"Do not worry. He is going to be happy just seeing your face.","TWN":"別擔心。老闆只要看到西格瑪的臉就會高興的。"},"stage":{"bg":"TRAINING","bgm":"THEMA_CA_SIGMA_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"TITAN_FAW_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L46_1","type":"dialog","speaker":"TITAN_FAW_NULL_NULL","text":{"KOREA":"이런, 벌써 순찰 임무를 갈 시간이군!","JPN":"おっと、そろそろ見回りに出る時間だ！","ENG":"Oh dear. It is time for me to go on a patrol!","TWN":"糟了，已經到了執行巡邏任務的時間了！"},"stage":{"bg":"TRAINING","bgm":"THEMA_CA_SIGMA_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"TITAN_FAW_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L47_1","type":"dialog","speaker":"SIGMA_RAS_NULL_NULL","text":{"KOREA":"오오, 순찰? 나도 갈래~.","JPN":"おお、見回り？　私も行きたい！","ENG":"Patrol? I want to go, too!","TWN":"喔喔，巡邏？我也要去～"},"stage":{"bg":"TRAINING","bgm":"THEMA_CA_SIGMA_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SIGMA_RAS_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L49_1","type":"dialog","speaker":"SIGMA_RAS_NULL_NULL","text":{"KOREA":"할아버지.","JPN":"おじいちゃん。","ENG":"Grandpa?","TWN":"爺爺。"},"stage":{"bg":"TRAINING","bgm":"THEMA_CA_SIGMA_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SIGMA_RAS_NULL_NULL","face":"UNIT_PRIDE"},"C":null,"R":null}}},{"id":"L50_1","type":"dialog","speaker":"TITAN_FAW_NULL_NULL","text":{"KOREA":"왜 그러나, 시그마?","JPN":"どうしたんだい、シグマ？","ENG":"What is it, Sigma?","TWN":"怎麼了，西格瑪？"},"stage":{"bg":"TRAINING","bgm":"THEMA_CA_SIGMA_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SIGMA_RAS_NULL_NULL","face":"UNIT_PRIDE"},"C":null,"R":{"char_id":"TITAN_FAW_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L1_1","type":"dialog","speaker":"SIGMA_RAS_NULL_NULL","text":{"KOREA":"다음에도… 다같이 이렇게 놀 수 있을까?","JPN":"また、こうしてみんなで遊べるかな？","ENG":"Do you think... we'll all be able to play together again?","TWN":"下次……還能和大家一起這樣玩嗎？"},"stage":{"bg":"TRAINING","bgm":"THEMA_CA_SIGMA_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SIGMA_RAS_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"TITAN_FAW_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L2_1","type":"dialog","speaker":"TITAN_FAW_NULL_NULL","text":{"KOREA":"물론이지! 시그마가 원한다면 다들 한걸음에 달려와줄 걸세!","JPN":"もちろんだ！　シグマが言えば、みんなすぐに来てくれるぞ！","ENG":"Of course! I have no doubt they will make their way here if you want!","TWN":"當然！只要西格瑪一聲令下，大家都會立刻趕來的！"},"stage":{"bg":"TRAINING","bgm":"THEMA_CA_SIGMA_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SIGMA_RAS_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"TITAN_FAW_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L3_1","type":"dialog","speaker":"SIGMA_RAS_NULL_NULL","text":{"KOREA":"히히. 정말~?","JPN":"ひひっ、ほんと～？","ENG":"Teehee. Really?","TWN":"嘻嘻，真的嗎～？"},"stage":{"bg":"TRAINING","bgm":"THEMA_CA_SIGMA_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SIGMA_RAS_NULL_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"TITAN_FAW_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L4_1","type":"dialog","speaker":"TITAN_FAW_NULL_NULL","text":{"KOREA":"하하, 정말이고 말고!","JPN":"はは！　本当だとも！","ENG":"Ha ha. Of course!","TWN":"哈哈，當然是真的！"},"stage":{"bg":"TRAINING","bgm":"THEMA_CA_SIGMA_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SIGMA_RAS_NULL_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"TITAN_FAW_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L8_1","type":"dialog","speaker":"SIGMA_RAS_NULL_NULL","text":{"KOREA":"맞다, 할아버지! 내가 안마해 줄게!","JPN":"そうだ、おじいちゃん！　マッサージしてあげる！","ENG":"Oh, Grandpa! Let me give you a massage!","TWN":"對了，爺爺！我來給你按摩！"},"stage":{"bg":"TRAINING","bgm":"THEMA_CA_SIGMA_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L9_1","type":"dialog","speaker":"TITAN_FAW_NULL_NULL","text":{"KOREA":"음? 갑자기 안마라니?","JPN":"うん？　どうしたんだい、急に。","ENG":"Mm? A massage?","TWN":"嗯？怎麼突然說要按摩？"},"stage":{"bg":"TRAINING","bgm":"THEMA_CA_SIGMA_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L10_1","type":"dialog","speaker":"SIGMA_RAS_NULL_NULL","text":{"KOREA":"나 할아버지 안마해주려고 엄청 연습했단 말이야~.","JPN":"私、おじいちゃんのために肩たたきたくさん練習したんだ！","ENG":"I practiced a lot to give you a massage, Grandpa!","TWN":"我可是為了給爺爺按摩，練習了很久呢～"},"stage":{"bg":"TRAINING","bgm":"THEMA_CA_SIGMA_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L11_1","type":"dialog","speaker":"SIGMA_RAS_NULL_NULL","text":{"KOREA":"빨리~ 빨리이~.","JPN":"ほらほら、早く～！","ENG":"Come on! Come oooon!","TWN":"快來～快來～"},"stage":{"bg":"TRAINING","bgm":"THEMA_CA_SIGMA_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}}]`);export{e as default};